create extension if not exists "pgcrypto";
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end $$;
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, avatar_url text, email text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.workspaces (id uuid primary key default gen_random_uuid(), owner_id uuid references auth.users(id) on delete cascade, name text not null, industry text, target_audience text, brand_tone text, content_goals text[], platforms text[], created_at timestamptz default now(), updated_at timestamptz default now());
create table public.workspace_members (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, user_id uuid references auth.users(id) on delete cascade, role text default 'owner', created_at timestamptz default now(), unique(workspace_id,user_id));
create table public.social_accounts (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, platform text not null, account_name text, account_handle text, provider_account_id text, connection_status text default 'connected', import_mode text default 'from_today', access_token_encrypted text, refresh_token_encrypted text, token_expires_at timestamptz, last_synced_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
alter table public.social_accounts add column if not exists scopes text[];
alter table public.social_accounts add column if not exists provider_meta jsonb;
create table public.campaigns (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, name text not null, goal text, status text default 'planned', start_date date, end_date date, platforms text[], created_at timestamptz default now(), updated_at timestamptz default now());
create table public.posts (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, social_account_id uuid references public.social_accounts(id) on delete set null, platform text not null, title text, caption text, content_type text, status text default 'published', campaign_id uuid references public.campaigns(id) on delete set null, content_goal text, media_url text, external_url text, posted_at timestamptz, scheduled_at timestamptz, likes integer default 0, comments integer default 0, shares integer default 0, saves integer default 0, reach integer default 0, impressions integer default 0, engagement_rate numeric default 0, duration_seconds integer, retention_rate numeric, source text default 'manual', external_post_id text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.content_ideas (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, title text not null, platform text, format text, goal text, priority text, status text default 'idea', notes text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.reports (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, report_type text, title text, date_range_start date, date_range_end date, total_posts integer default 0, total_reach integer default 0, total_engagement integer default 0, average_engagement_rate numeric default 0, top_post_id uuid references public.posts(id) on delete set null, recommendations text[], created_at timestamptz default now());
create table public.chat_messages (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, role text not null, content text not null, created_at timestamptz default now());
create table public.analytics_snapshots (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, social_account_id uuid references public.social_accounts(id) on delete cascade, platform text not null, snapshot_date date not null, followers integer default 0, total_posts integer default 0, total_reach integer default 0, total_impressions integer default 0, total_engagement integer default 0, average_engagement_rate numeric default 0, created_at timestamptz default now());
create table public.demo_seed_runs (workspace_id uuid primary key references public.workspaces(id) on delete cascade, created_at timestamptz default now());
create table public.oauth_states (id uuid primary key default gen_random_uuid(), workspace_id uuid references public.workspaces(id) on delete cascade, user_id uuid references auth.users(id) on delete cascade, provider text not null, state_hash text not null unique, code_verifier text, import_mode text default 'from_today', created_at timestamptz default now(), expires_at timestamptz not null default now() + interval '10 minutes');
create index on public.workspaces(owner_id); create index on public.workspace_members(user_id); create index on public.social_accounts(workspace_id); create index on public.social_accounts(platform); create unique index social_accounts_workspace_platform_handle_key on public.social_accounts(workspace_id,platform,account_handle); create unique index posts_workspace_platform_external_key on public.posts(workspace_id,platform,external_post_id); create index on public.posts(workspace_id); create index on public.posts(platform); create index on public.posts(posted_at); create index on public.posts(scheduled_at); create index on public.campaigns(workspace_id); create index on public.content_ideas(workspace_id); create index on public.reports(workspace_id); create index on public.chat_messages(workspace_id); create index on public.analytics_snapshots(workspace_id); create index on public.oauth_states(workspace_id); create index on public.oauth_states(expires_at);
create or replace function public.is_workspace_member(target uuid) returns boolean language sql security definer set search_path=public stable as $$ select exists(select 1 from public.workspace_members where workspace_id=target and user_id=auth.uid()) $$;
alter table public.profiles enable row level security; alter table public.workspaces enable row level security; alter table public.workspace_members enable row level security; alter table public.social_accounts enable row level security; alter table public.posts enable row level security; alter table public.content_ideas enable row level security; alter table public.campaigns enable row level security; alter table public.reports enable row level security; alter table public.chat_messages enable row level security; alter table public.analytics_snapshots enable row level security; alter table public.demo_seed_runs enable row level security; alter table public.oauth_states enable row level security;
create policy "own profile" on public.profiles for all using(id=auth.uid()) with check(id=auth.uid());
create policy "workspace members" on public.workspaces for select using(owner_id=auth.uid() or public.is_workspace_member(id)); create policy "create workspace" on public.workspaces for insert with check(owner_id=auth.uid()); create policy "update own workspace" on public.workspaces for update using(owner_id=auth.uid()) with check(owner_id=auth.uid());
create policy "members visible" on public.workspace_members for select using(user_id=auth.uid() or public.is_workspace_member(workspace_id)); create policy "owner adds members" on public.workspace_members for insert with check(exists(select 1 from public.workspaces where id=workspace_id and owner_id=auth.uid()));
create policy "member social accounts" on public.social_accounts for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member posts" on public.posts for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member ideas" on public.content_ideas for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member campaigns" on public.campaigns for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member reports" on public.reports for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member chat" on public.chat_messages for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member snapshots" on public.analytics_snapshots for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member demo seed runs" on public.demo_seed_runs for all using(public.is_workspace_member(workspace_id)) with check(public.is_workspace_member(workspace_id));
create policy "member oauth states" on public.oauth_states for all using(public.is_workspace_member(workspace_id) and user_id=auth.uid()) with check(public.is_workspace_member(workspace_id) and user_id=auth.uid());
create trigger workspaces_updated before update on public.workspaces for each row execute function public.set_updated_at(); create trigger social_accounts_updated before update on public.social_accounts for each row execute function public.set_updated_at(); create trigger posts_updated before update on public.posts for each row execute function public.set_updated_at(); create trigger ideas_updated before update on public.content_ideas for each row execute function public.set_updated_at(); create trigger campaigns_updated before update on public.campaigns for each row execute function public.set_updated_at();
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name,avatar_url) values(new.id,new.email,new.raw_user_meta_data->>'full_name',new.raw_user_meta_data->>'avatar_url'); return new; end $$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create or replace function public.handle_new_workspace() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.workspace_members(workspace_id,user_id,role) values(new.id,new.owner_id,'owner'); return new; end $$;
create trigger on_workspace_created after insert on public.workspaces for each row execute function public.handle_new_workspace();
revoke select on public.social_accounts from anon, authenticated;
grant select(id,workspace_id,platform,account_name,account_handle,provider_account_id,connection_status,import_mode,token_expires_at,last_synced_at,created_at,updated_at,scopes,provider_meta) on public.social_accounts to authenticated;
revoke insert,update on public.social_accounts from anon, authenticated;
grant insert(workspace_id,platform,account_name,account_handle,provider_account_id,connection_status,import_mode,last_synced_at,scopes,provider_meta) on public.social_accounts to authenticated;
grant update(account_name,account_handle,provider_account_id,connection_status,import_mode,last_synced_at,scopes,provider_meta) on public.social_accounts to authenticated;
revoke all on function public.is_workspace_member(uuid) from public;
grant execute on function public.is_workspace_member(uuid) to authenticated;
notify pgrst, 'reload schema';

